mapper.select:
select id                                        id,
       stock_virtual_no                          stockVirtualNo,
       contract_type                             contractType,
       company_name                              companyName,
       product_name                              productName,
       factory_name                              factoryName,
       brand_number                              brandNumber,
       deal_number                               dealNumber,
       deal_price                                dealPrice,
       total_amount                              totalAmount,
       date_format(delivery_date, '%Y-%m-%d')    deliveryDate,
       date_format(pay_full_time, '%Y-%m-%d')    payFullTime,
       date_format(publish_time, '%Y-%m-%d')     publicTime,
       delivery_type                             'deliveryType',
       date_format(arrival_time_ext, '%Y-%m-%d') arrivalTimeExt,
       status                                    status,
       delivery_addr                             deliveryAddr,
       match_user_name                           matchUserName
from t_stock_virtual


        contract_type = #{contractTypeSearch}


        and company_name like concat('%',#{companyNameSearch},'%')


        and product_name = #{productNameSearch}


        and brand_number = #{brandNumberSearch}


        and factory_name = #{factoryNameSearch}


        and deal_number between #{minDealNumberSearch} and  #{maxDealNumberSearch}


         and deal_number >= #{minDealNumberSearch} 


         and deal_number <= #{maxDealNumberSearch} 


        and wrap_specs = #{wrapSpecsSearch}


        and quality_standard = #{qualityStandardSearch}



order by id desc
